const image = $input.first().json.body.image;

if (!image) throw new Error('Missing image field in request body');

const payload = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 1024,
  messages: [
    {
      role: 'user',
      content: [
        {
          type: 'image',
          source: {
            type: 'base64',
            media_type: 'image/jpeg',
            data: image
          }
        },
        {
          type: 'text',
          text: 'Prüfe diese Ausgangsrechnung auf die Pflichtangaben gemäß §14 UStG und antworte als JSON:\n{ "has_vendor_name": true, "has_vendor_address": true, "has_recipient_name": true, "has_recipient_address": true, "has_tax_number_or_uid": true, "has_invoice_date": true, "has_invoice_number": true, "has_service_description": true, "has_service_period": true, "has_net_amount": true, "has_vat_rate_and_amount": true, "has_gross_amount": true, "missing_fields": [], "is_compliant": true, "notes": "..." }\nAntworte NUR mit dem JSON-Objekt.'
        }
      ]
    }
  ]
};

return [{ json: { payload } }];

const text = $input.first().json.content[0].text;

let compliance;
try {
  compliance = JSON.parse(text);
} catch {
  throw new Error('Claude did not return valid JSON: ' + text.substring(0, 200));
}

return [{ json: compliance }];
